// ── Family-only entry gate ────────────────────────────────────────────────────
// Aurame OS is a sovereign family workspace. Visitors must sign in via the
// landing page (aurame.ca) — which sets aura_session in localStorage — before
// the OS shell will render. Anyone arriving without a session is shown a
// "Sign in at aurame.ca" gate.
function useFamilySession(): "checking" | "signed-in" | "guest" {
  const [status, setStatus] = useState<"checking" | "signed-in" | "guest">("checking");
  useEffect(() => {
    try {
      const raw = localStorage.getItem("aura_session");
      if (raw) {
        const s = JSON.parse(raw);
        if (s?.auraId || s?.aura_id) {
          setStatus("signed-in");
          return;
        }
      }
    } catch {}
    setStatus("guest");
  }, []);
  return status;
}

