                  style={{ width: 6, height: 6, borderRadius: '50%', background: '#38bdf8' }} />
              ))}
            </div>
          </motion.div>
        )}
        <div ref={bottomRef} />
      </div>

      {/* Input */}
      <div style={{ padding: '10px 16px', borderTop: '1px solid rgba(56,189,248,0.1)', display: 'flex', gap: 8, flexShrink: 0 }}>
        <input
          ref={inputRef}
