  sov:      () => <SOVWalletApp />,
  syncity:  () => <SynCityApp />,
  clock:     () => <ClockApp />,
  phone:     () => <PhoneApp />,
  personal:  () => <PersonalApp />,
  family:    () => <FamilyApp />,
  business:  () => <BusinessApp />,
  rental:    () => <RentalApp />,
  maps:      () => <MapsApp />,
