function RobotFace({ color, size = 32, speaking = false }: { color: string; size?: number; speaking?: boolean }) {
  return (
    <svg viewBox="0 0 100 110" width={size} height={size} overflow="visible">
      <defs>
        <linearGradient id="orb-rb" x1="0%" y1="0%" x2="100%" y2="100%">
          <stop offset="0%" stopColor="white" stopOpacity="0.95" />
          <stop offset="100%" stopColor={color} />
        </linearGradient>
      </defs>
      <line x1="50" y1="28" x2="50" y2="18" stroke={color} strokeWidth="3" strokeLinecap="round" />
      <circle cx="50" cy="15" r="3.5" fill="#fbbf24" />
      <circle cx="50" cy="58" r="30" fill="url(#orb-rb)" />
      <rect x="12" y="50" width="8" height="15" rx="4" fill="#1e293b" opacity="0.3" />
      <rect x="80" y="50" width="8" height="15" rx="4" fill="#1e293b" opacity="0.3" />
      <rect x="28" y="46" width="44" height="16" rx="5" fill="#0f172a" opacity="0.85" />
      <rect x="33" y="50" width="10" height="8" rx="2" fill={color} opacity="0.95" />
      <rect x="57" y="50" width="10" height="8" rx="2" fill={color} opacity="0.95" />
      {speaking ? (
        <motion.path
          d="M 40 76 Q 50 82 60 76" stroke="#1e293b" strokeWidth="2.5" fill="none" strokeLinecap="round"
