interface PebbleOrbProps {
  onOpen: () => void;
}

export function PebbleOrb({ onOpen }: PebbleOrbProps) {
  const [hint, setHint] = useState(false);
  const [justTeleported, setJustTeleported] = useState(false);

  // Show "just teleported" sparkle briefly on first mount
  useEffect(() => {
    setJustTeleported(true);
    const t = setTimeout(() => setJustTeleported(false), 3000);
    return () => clearTimeout(t);
  }, []);

  const color = '#38bdf8'; // Pebble Vibe skin default

  return (
    <div style={{ position: 'fixed', bottom: 80, right: 20, zIndex: 850, display: 'flex', flexDirection: 'column', alignItems: 'flex-end', gap: 8 }}>

      {/* "Just teleported" badge */}
      <AnimatePresence>
        {justTeleported && (
          <motion.div
            initial={{ opacity: 0, y: 8, scale: 0.85 }}
            animate={{ opacity: 1, y: 0, scale: 1 }}
            exit={{ opacity: 0, y: 8, scale: 0.85 }}
            transition={{ type: 'spring', damping: 20 }}
            style={{
              background: 'rgba(8,6,24,0.88)',
              border: '1px solid rgba(56,189,248,0.3)',
              borderRadius: 12,
              padding: '6px 12px',
              fontSize: 11,
              fontWeight: 700,
              color: '#38bdf8',
              whiteSpace: 'nowrap',
              backdropFilter: 'blur(16px)',
              boxShadow: '0 4px 20px rgba(0,0,0,0.4)',
            }}
          >
            ✦ Pebble is here with you
          </motion.div>
        )}
      </AnimatePresence>

      {/* Hint tooltip */}
      <AnimatePresence>
        {hint && !justTeleported && (
          <motion.div
            initial={{ opacity: 0, y: 6 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: 6 }}
            style={{
              background: 'rgba(8,6,24,0.88)',
              border: '1px solid rgba(255,255,255,0.1)',
              borderRadius: 10,
              padding: '5px 12px',
              fontSize: 11,
              fontWeight: 600,
              color: 'rgba(255,255,255,0.8)',
              whiteSpace: 'nowrap',
              backdropFilter: 'blur(16px)',
            }}
          >
            Open Pebble Intelligence
          </motion.div>
        )}
      </AnimatePresence>

      {/* The orb button */}
      <motion.button
        onHoverStart={() => setHint(true)}
        onHoverEnd={() => setHint(false)}
        onClick={onOpen}
        whileHover={{ scale: 1.1, y: -4 }}
        whileTap={{ scale: 0.92 }}
        animate={{
          y: [0, -5, 0],
          filter: [`drop-shadow(0 6px 20px ${color}60)`, `drop-shadow(0 10px 28px ${color}90)`, `drop-shadow(0 6px 20px ${color}60)`],
        }}
        transition={{ y: { duration: 3, repeat: Infinity, ease: 'easeInOut' }, filter: { duration: 3, repeat: Infinity, ease: 'easeInOut' } }}
        style={{ background: 'none', border: 'none', cursor: 'pointer', padding: 0, outline: 'none', display: 'block', position: 'relative' }}
        aria-label="Open Pebble"
      >
        <RobotFace color={color} size={48} />

        {/* Online dot */}
        <span style={{
          position: 'absolute',
          bottom: 6,
          right: 2,
          width: 10,
          height: 10,
          borderRadius: '50%',
          background: '#34d399',
          border: '2px solid rgba(8,6,24,0.8)',
          boxShadow: '0 0 6px #34d399',
        }} />
      </motion.button>
    </div>
  );
}
