'use client';

import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  Building2, Layout, Globe, 
  Settings, User, LogOut,
  ShieldCheck, Sparkles, Plus,
  ChevronRight, Database, LayoutGrid
} from 'lucide-react';
import { useUser, useFirebase, useDoc, useMemoFirebase, signInWithGoogle } from './firebase';
import { AuraRegistry } from './components/features/AuraRegistry';
import { AuraRentals } from './components/features/AuraRentals';
import { RentersCustomPortal } from './components/features/RentersCustomPortal';
import { Button } from './components/ui/button';
import { doc, collection, query, where, getDocs, limit } from 'firebase/firestore';
import { cn } from './lib/utils';
import { Loader2 } from 'lucide-react';

export default function App() {
  const { user, isUserLoading } = useUser();
  const { auth, firestore } = useFirebase();
  const [view, setView] = useState<'admin' | 'portal-builder'>('admin');
  const [universe, setUniverse] = useState<any>(null);
  const [isRegistryOpen, setIsRegistryOpen] = useState(false);
  const [isSigningIn, setIsSigningIn] = useState(false);

  // Fetch Universe for the user
  useEffect(() => {
    if (!user || !firestore) return;
    const fetchUniverse = async () => {
      const q = query(
        collection(firestore, 'family_universes'), 
        where('ownerMemberId', '==', user.uid), 
        limit(1)
      );
      const snap = await getDocs(q);
      if (!snap.empty) {
        setUniverse({ id: snap.docs[0].id, ...snap.docs[0].data() });
      } else {
        setIsRegistryOpen(true);
      }
    };
    fetchUniverse();
  }, [user, firestore]);

  const handleSignIn = async () => {
    setIsSigningIn(true);
    try {
      await signInWithGoogle();
    } catch (error) {
      console.error("Sign-in failed:", error);
    } finally {
      setIsSigningIn(false);
    }
  };

  if (isUserLoading) {
    return (
      <div className="h-screen w-full flex items-center justify-center bg-slate-50">
        <div className="flex flex-col items-center gap-6">
          <div className="w-16 h-16 bg-slate-900 rounded-[2rem] flex items-center justify-center text-white shadow-2xl animate-pulse">
            <Building2 size={32} />
          </div>
          <p className="text-[10px] font-black uppercase tracking-[0.5em] text-slate-400">Initializing Aura Rent...</p>
        </div>
      </div>
    );
  }

  if (!user) {
    return (
      <div className="h-screen w-full flex items-center justify-center bg-slate-50 p-6">
        <div className="max-w-md w-full bg-white border border-slate-100 rounded-[3rem] p-12 shadow-2xl text-center space-y-10">
          <div className="flex flex-col items-center gap-6">
            <div className="w-20 h-20 bg-slate-900 rounded-[2.5rem] flex items-center justify-center text-white shadow-2xl">
              <Building2 size={40} className="text-[#D4AF37]" />
            </div>
            <div className="space-y-2">
              <h1 className="text-3xl font-black italic tracking-tighter uppercase text-slate-900">Aura Rent Protocol</h1>
              <p className="text-[10px] font-black uppercase tracking-[0.4em] text-indigo-500">Sovereign Property Ecosystem</p>
            </div>
          </div>
          
          <div className="space-y-4">
            <Button 
              onClick={handleSignIn}
              disabled={isSigningIn}
              className="w-full py-8 rounded-[2rem] bg-slate-900 text-white font-black uppercase tracking-[0.3em] h-auto shadow-xl hover:bg-indigo-600 transition-all"
            >
              {isSigningIn ? <Loader2 className="animate-spin mr-2" /> : null}
              Initialize Connection
            </Button>
            <p className="text-[9px] font-bold text-slate-400 uppercase tracking-widest leading-relaxed">
              Access to the Rent Protocol requires a verified Aura Identity.
            </p>
          </div>
        </div>
      </div>
    );
  }

  if (isRegistryOpen && !universe) {
    return (
      <div className="h-screen w-full flex items-center justify-center bg-slate-900/10 backdrop-blur-sm">
        <div className="bg-white rounded-[4rem] shadow-[0_40px_100px_rgba(0,0,0,0.1)] overflow-hidden max-w-2xl w-full">
          <AuraRegistry 
            onSuccess={() => {
              setIsRegistryOpen(false);
              window.location.reload();
            }} 
            onCancel={() => setIsRegistryOpen(false)} 
          />
        </div>
      </div>
    );
  }

  return (
    <div className="h-screen w-full flex flex-col bg-white overflow-hidden">
      {/* Global Navigation Rail */}
      <nav className="h-20 border-b border-slate-100 flex items-center justify-between px-10 bg-white shrink-0 z-[100]">
        <div className="flex items-center gap-8">
          <div className="flex items-center gap-4">
            <div className="w-10 h-10 bg-slate-900 rounded-xl flex items-center justify-center text-[#D4AF37] italic font-black shadow-lg">A</div>
            <div className="text-left">
              <h1 className="text-sm font-black uppercase tracking-tighter italic leading-none">Aura Rent</h1>
              <p className="text-[8px] font-black uppercase tracking-[0.3em] text-indigo-500 mt-1">{universe?.name || 'Sanctuary'}</p>
            </div>
          </div>
          
          <div className="h-8 w-px bg-slate-100" />
          
          <div className="flex gap-2">
            <button 
              onClick={() => setView('admin')}
              className={cn(
                "px-6 py-2.5 rounded-xl text-[9px] font-black uppercase tracking-widest transition-all flex items-center gap-2",
                view === 'admin' ? "bg-slate-900 text-white shadow-lg" : "text-slate-400 hover:bg-slate-50"
              )}
            >
              <Database size={14} /> Registry
            </button>
            <button 
              onClick={() => setView('portal-builder')}
              className={cn(
                "px-6 py-2.5 rounded-xl text-[9px] font-black uppercase tracking-widest transition-all flex items-center gap-2",
                view === 'portal-builder' ? "bg-slate-900 text-white shadow-lg" : "text-slate-400 hover:bg-slate-50"
              )}
            >
              <Globe size={14} /> Portal Builder
            </button>
          </div>
        </div>

        <div className="flex items-center gap-6">
          <div className="flex items-center gap-3 px-4 py-2 bg-slate-50 rounded-full border border-slate-100">
            <div className="w-6 h-6 rounded-full bg-indigo-500 flex items-center justify-center text-[8px] text-white font-black">P1</div>
            <span className="text-[9px] font-black uppercase tracking-widest text-slate-600">{user.displayName || user.email?.split('@')[0]}</span>
          </div>
          <button 
            onClick={() => auth.signOut()}
            className="p-3 text-slate-300 hover:text-rose-500 transition-colors"
          >
            <LogOut size={20} />
          </button>
        </div>
      </nav>

      <main className="flex-1 relative overflow-hidden">
        <AnimatePresence mode="wait">
          {view === 'admin' && (
            <motion.div 
              key="admin-view"
              initial={{ opacity: 0, x: -20 }}
              animate={{ opacity: 1, x: 0 }}
              exit={{ opacity: 0, x: -20 }}
              className="h-full w-full"
            >
              <AuraRentals memberId={user.uid} universeId={universe?.id} />
            </motion.div>
          )}
          {view === 'portal-builder' && (
            <motion.div 
              key="portal-view"
              initial={{ opacity: 0, x: 20 }}
              animate={{ opacity: 1, x: 0 }}
              exit={{ opacity: 0, x: 20 }}
              className="h-full w-full"
            >
              <RentersCustomPortal 
                slug={universe?.slug || 'my-portal'} 
                ablid={user.uid} 
                onClose={() => setView('admin')} 
              />
            </motion.div>
          )}
        </AnimatePresence>
      </main>
    </div>
  );
}
import React, { memo } from 'react';
import { cn } from '../../lib/utils';

export const AuraLogo = memo(({ size = "md", active = false }: { size?: "sm" | "md" | "lg", active?: boolean }) => {
  const sizeClasses = { 
    sm: "w-8 h-8 text-sm", 
    md: "w-10 h-10 text-lg", 
    lg: "w-14 h-14 text-2xl" 
  };

  return (
    <div className={cn(
      "flex items-center justify-center rounded-2xl shadow-lg font-black text-white italic relative overflow-hidden group transition-all duration-500",
      "bg-gradient-to-br from-[#ff4eb1] via-[#c24ef4] to-[#7c3aed]",
      active && "shadow-[0_0_20px_rgba(194,78,244,0.4)] scale-105",
      sizeClasses[size]
    )}>
      <div className="absolute inset-0 bg-gradient-to-tr from-white/20 to-transparent pointer-events-none" />
      <span className="relative z-10 drop-shadow-md">A</span>
    </div>
  );
});

AuraLogo.displayName = 'AuraLogo';'use client';

import React, { useState, useEffect, useMemo } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  Building2, Plus, Loader2, Sparkles, 
  ChevronRight, Database, LayoutGrid,
  ShieldCheck, Globe, ChevronLeft,
  Briefcase, Landmark, Scale, Lock,
  Fingerprint, Save, Info, AlertTriangle,
  Zap, CheckCircle2, Cpu, MapPin, X, DollarSign, Image, Tag,
  Layout, Activity, Settings, User, Bell, Search, Filter
} from 'lucide-react';
import { useFirestore, useCollection, useMemoFirebase, useDoc } from '../../firebase';
import { collection, doc, setDoc, serverTimestamp, addDoc } from 'firebase/firestore';
import { PortfolioOverview } from './rent/PortfolioOverview';
import { BuildingCommandCenter } from './rent/BuildingCommandCenter';
import { SettingsOverlay } from './rent/SettingsOverlay';
import { GlobalAssetVisualizer } from './rent/GlobalAssetVisualizer';
import { cn } from '../../lib/utils';

import { calculatePricing } from '../../services/PricingService';

export const AuraRentals = ({ memberId, universeId, forceReview = false }: { memberId: string; universeId: string; forceReview?: boolean }) => {
  const db = useFirestore();
  const [activePropertyId, setActivePropertyId] = useState<string | null>(null);
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [isGlobalVisualizerOpen, setIsGlobalVisualizerOpen] = useState(false);
  
  // Forge (Add Property) State
  const [isForging, setIsForging] = useState(false);
  const [forgeStep, setForgeStep] = useState(1);
  const [isSavingForge, setIsSavingForge] = useState(false);
  const [forgeData, setForgeData] = useState({
    name: '',
    address: '',
    lat: 46.4917,
    lng: -80.9930,
    units: [{ 
      id: '1', 
      name: 'Unit 101', 
      price: 2000, 
      type: 'Residential' as 'Short-term' | 'Residential' | 'Commercial', 
      images: [''],
      description: ''
    }]
  });
  const [acceptCosts, setAcceptCosts] = useState(false);

  // Covenant State
  const [isCovenantSigned, setIsCovenantSigned] = useState<boolean | null>(null);
  const [isSigning, setIsSigning] = useState(false);
  const [signature, setSignature] = useState("");
  const [agreements, setAgreements] = useState({
    msa: false,
    pricing: false,
    pipeda: false
  });

  // Data Selectors
  const propertiesRef = useMemoFirebase(() => {
    if (!db || !universeId || !memberId) return null;
    return collection(db, 'family_universes', universeId, 'members', memberId, 'properties');
  }, [db, universeId, memberId]);

  const { data: properties, isLoading } = useCollection(propertiesRef);

  const configRef = useMemoFirebase(() => {
    if (!db || !universeId || !memberId) return null;
    return doc(db, 'family_universes', universeId, 'members', memberId, 'config', 'rent_protocol');
  }, [db, universeId, memberId]);

  const { data: rentConfig, isLoading: isConfigLoading } = useDoc(configRef);

  useEffect(() => {
    if (!isConfigLoading) {
      setIsCovenantSigned(!!rentConfig?.signedAt);
      if (rentConfig?.signature) setSignature(rentConfig.signature);
      if (rentConfig?.agreements) setAgreements(rentConfig.agreements);
    }
  }, [rentConfig, isConfigLoading]);

  // Pricing Matrix Logic
  const billingMetrics = useMemo(() => {
    return calculatePricing(properties || []);
  }, [properties]);

  const handleSignCovenant = async () => {
    if (!configRef || isSigning) return;
    setIsSigning(true);
    try {
      await setDoc(configRef, {
        signedAt: serverTimestamp(),
        signature,
        agreements,
        status: 'Active'
      }, { merge: true });
      setIsCovenantSigned(true);
    } catch (e) {
      console.error(e);
    } finally {
      setIsSigning(false);
    }
  };

  const handleForgeSave = async () => {
    if (!propertiesRef || isSavingForge) return;
    setIsSavingForge(true);
    try {
      await addDoc(propertiesRef, {
        ...forgeData,
        createdAt: serverTimestamp(),
        isAirbnb: forgeData.units.some(u => u.type === 'Short-term'),
        rent: forgeData.units.reduce((acc, u) => acc + u.price, 0),
        avatar: `https://api.dicebear.com/7.x/identicon/svg?seed=${forgeData.name}`
      });
      setIsForging(false);
      setForgeStep(1);
      setForgeData({ 
        name: '', 
        address: '', 
        lat: 46.4917, 
        lng: -80.9930, 
        units: [{ id: '1', name: 'Unit 101', price: 2000, type: 'Residential', images: [''], description: '' }] 
      });
      setAcceptCosts(false);
    } catch (e) {
      console.error(e);
    } finally {
      setIsSavingForge(false);
    }
  };

  const selectedProperty = useMemo(() => 
    properties?.find(p => p.id === activePropertyId), 
    [properties, activePropertyId]
  );

  if (isLoading || isConfigLoading || isCovenantSigned === null) {
    return <div className="h-full flex items-center justify-center"><Loader2 className="animate-spin text-slate-300" size={32} /></div>;
  }

  if (!isCovenantSigned || forceReview) {
    const isFormValid = signature.length > 5 && Object.values(agreements).every(Boolean);

    return (
      <div className="h-full flex flex-col p-10 bg-white items-center justify-center overflow-y-auto custom-scrollbar">
        <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} className="max-w-3xl w-full space-y-12 py-10 text-left">
          <div className="flex flex-col items-center text-center space-y-6 mb-12">
            <div className="w-20 h-20 bg-slate-900 rounded-[2.5rem] flex items-center justify-center text-white shadow-2xl relative">
              <Building2 size={40} className="text-[#D4AF37]" />
              <div className="absolute -bottom-2 -right-2 w-8 h-8 bg-indigo-600 rounded-full border-4 border-white flex items-center justify-center shadow-lg">
                <Zap size={14} fill="currentColor" />
              </div>
            </div>
            <div>
              <h2 className="text-4xl font-black italic tracking-tighter uppercase text-slate-900">Aura Rent Protocol</h2>
              <p className="text-[10px] font-black uppercase tracking-[0.5em] text-indigo-500 mt-2">
                {forceReview ? 'Registry Covenant Review' : 'Initialize Sovereign Property Registry'}
              </p>
            </div>
          </div>

          <div className="bg-slate-50/50 border border-slate-100 rounded-[3.5rem] p-10 space-y-10 shadow-inner">
            <div className="space-y-4">
              <h3 className="text-sm font-black uppercase tracking-widest text-slate-900 underline decoration-indigo-500/30 decoration-4 underline-offset-4">Contractual Entry</h3>
              <p className="text-xs font-medium text-slate-400 uppercase tracking-widest leading-relaxed">Institutional Terms & Sovereign Economy Clauses.</p>
            </div>

            <div className="space-y-3">
              {[
                { id: 'msa', title: 'Master Service Agreement', text: 'Full acceptance of Aura Infrastructure terms. Governed by the Electronic Commerce Act (ECA).' },
                { id: 'pricing', title: 'SOV Economy & Genesis', text: 'Agreement to 60 SOV/unit flat fee. Recognition of the 5-Unit Genesis Credit.' },
                { id: 'pipeda', title: 'Privacy & Biometric Consent', text: 'Explicit consent for processing personal information under PIPEDA.' }
              ].map(clause => (
                <button 
                  key={clause.id}
                  disabled={forceReview}
                  onClick={() => setAgreements(prev => ({ ...prev, [clause.id]: !prev[clause.id as keyof typeof agreements] }))}
                  className={cn(
                    "w-full text-left p-6 rounded-3xl border-2 transition-all group",
                    agreements[clause.id as keyof typeof agreements] ? "bg-indigo-50 border-indigo-200" : "bg-white border-slate-100 hover:border-slate-200"
                  )}
                >
                  <div className="flex gap-5 items-start">
                    <div className={cn(
                      "mt-1 w-6 h-6 rounded-lg border-2 flex items-center justify-center transition-all",
                      agreements[clause.id as keyof typeof agreements] ? "bg-indigo-600 border-indigo-600 text-white shadow-md" : "border-slate-200"
                    )}>
                      {agreements[clause.id as keyof typeof agreements] && <CheckCircle2 size={14} strokeWidth={3} />}
                    </div>
                    <div>
                      <p className={cn("text-[11px] font-black uppercase tracking-widest mb-1", agreements[clause.id as keyof typeof agreements] ? "text-indigo-900" : "text-slate-900")}>{clause.title}</p>
                      <p className="text-[10px] leading-relaxed font-bold text-slate-400 uppercase tracking-tight">{clause.text}</p>
                    </div>
                  </div>
                </button>
              ))}
            </div>

            <div className="space-y-4 pt-4 text-left">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-2">Digital Sovereign Signature</label>
              <div className="relative">
                <input 
                  disabled={forceReview}
                  value={signature}
                  onChange={(e) => setSignature(e.target.value.toUpperCase())}
                  placeholder="FULL LEGAL NAME"
                  className="w-full p-8 bg-white border-2 border-slate-100 rounded-[2.5rem] text-3xl font-black italic tracking-tighter uppercase outline-none focus:border-indigo-600 transition-all text-center placeholder:text-slate-100 shadow-sm disabled:opacity-50"
                />
                <Fingerprint className={cn("absolute right-8 top-1/2 -translate-y-1/2 transition-colors", signature.length > 5 ? "text-indigo-500" : "text-slate-100")} size={32} />
              </div>
            </div>

            {!forceReview ? (
              <button 
                disabled={!isFormValid || isSigning}
                onClick={handleSignCovenant}
                className="w-full py-8 bg-slate-900 text-white rounded-[2.5rem] font-black uppercase text-[12px] tracking-[0.4em] shadow-2xl hover:bg-indigo-600 transition-all active:scale-95 disabled:opacity-20 flex items-center justify-center gap-4"
              >
                {isSigning ? <Loader2 className="animate-spin" /> : <><ShieldCheck size={20} /> Authorize Registry Anchor</>}
              </button>
            ) : (
              <div className="p-6 bg-indigo-600 text-white rounded-[2rem] text-center font-black uppercase text-[10px] tracking-[0.4em] shadow-xl">
                Registry Active // Verified Node
              </div>
            )}
          </div>
        </motion.div>
      </div>
    );
  }

  return (
    <div className="h-full flex bg-[#0A0B10] text-white overflow-hidden font-sans selection:bg-indigo-500/30">
      {/* Cinematic Sidebar Rail */}
      <div className="w-16 border-r border-white/5 flex flex-col items-center py-4 gap-4 z-50 bg-[#0A0B10]/80 backdrop-blur-xl">
        <div className="w-8 h-8 bg-indigo-600 rounded-lg flex items-center justify-center shadow-2xl shadow-indigo-500/20 group cursor-pointer hover:scale-110 transition-all duration-500">
          <Building2 size={16} className="text-white group-hover:rotate-12 transition-transform" />
        </div>
        
        <div className="flex-1 flex flex-col gap-2 overflow-y-auto custom-scrollbar px-2 no-scrollbar">
          {properties?.map((p: any) => (
            <motion.button
              key={p.id}
              whileHover={{ scale: 1.1 }}
              whileTap={{ scale: 0.95 }}
              onClick={() => setActivePropertyId(p.id)}
              className={cn(
                "w-10 h-10 rounded-lg flex items-center justify-center transition-all duration-300 relative group",
                activePropertyId === p.id 
                  ? "bg-white text-slate-900 shadow-[0_0_20px_rgba(255,255,255,0.2)]" 
                  : "bg-white/5 text-slate-400 hover:bg-white/10"
              )}
            >
              <img 
                src={p.avatar || `https://api.dicebear.com/7.x/identicon/svg?seed=${p.id}`} 
                alt="" 
                className={cn("w-6 h-6 object-cover rounded-md transition-all", activePropertyId === p.id ? "opacity-100" : "opacity-40 group-hover:opacity-100")} 
              />
              {activePropertyId === p.id && (
                <motion.div layoutId="active-indicator" className="absolute -left-2 w-1 h-5 bg-white rounded-full" />
              )}
            </motion.button>
          ))}
          
          <button 
