import { getAuth, onAuthStateChanged, User, signInWithPopup, GoogleAuthProvider } from 'firebase/auth';
import { getFirestore, collection, doc, onSnapshot, Query, DocumentReference } from 'firebase/firestore';
import { useState, useEffect, useMemo } from 'react';
import firebaseConfig from '../firebase-applet-config.json';

const app = initializeApp(firebaseConfig);
export const auth = getAuth(app);
export const db = getFirestore(app, firebaseConfig.firestoreDatabaseId);

export function signInWithGoogle() {
  const provider = new GoogleAuthProvider();
  return signInWithPopup(auth, provider);
}

export function useFirebase() {
  return { auth, firestore: db };
}

export function useUser() {
  const [user, setUser] = useState<User | null>(null);
  const [isUserLoading, setIsUserLoading] = useState(true);

  useEffect(() => {
    return onAuthStateChanged(auth, (user) => {
      setUser(user);
      setIsUserLoading(false);
    });
  }, []);

  return { user, isUserLoading };
}

export function useFirestore() {
  return db;
}

export function useCollection(ref: Query | null) {
  const [data, setData] = useState<any[] | null>(null);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    if (!ref) {
      setData(null);
      setIsLoading(false);
      return;
    }

    setIsLoading(true);
    return onSnapshot(ref, (snap) => {
      setData(snap.docs.map(d => ({ id: d.id, ...d.data() })));
      setIsLoading(false);
    }, (err) => {
      console.error("Firestore Collection Error:", err);
      setIsLoading(false);
    });
  }, [ref]);

  return { data, isLoading };
}

export function useDoc(ref: DocumentReference | null) {
  const [data, setData] = useState<any | null>(null);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    if (!ref) {
      setData(null);
      setIsLoading(false);
      return;
    }

    setIsLoading(true);
    return onSnapshot(ref, (snap) => {
      setData(snap.exists() ? { id: snap.id, ...snap.data() } : null);
      setIsLoading(false);
    }, (err) => {
      console.error("Firestore Doc Error:", err);
      setIsLoading(false);
    });
  }, [ref]);

  return { data, isLoading };
}

export function useMemoFirebase<T>(factory: () => T, deps: any[]) {
  return useMemo(factory, deps);
}
