export interface PricingMetrics {
  freeUnits: number;
  paidUnits: number;
  totalCost: number;
  remainingFreeAllowance: number;
}

/**
 * Aura Rent Protocol Pricing Logic:
 * 1. The first 5 units provisioned across all buildings are free.
 * 2. All subsequent units are paid at $60/mo.
 * 3. The first building (Genesis Node) cannot be deleted to preserve the free allowance.
 */
export const calculatePricing = (properties: any[]): PricingMetrics => {
  if (!properties || properties.length === 0) {
    return { freeUnits: 0, paidUnits: 0, totalCost: 0, remainingFreeAllowance: 5 };
  }

  // Sort by creation time to identify the provisioning order
  const sorted = [...properties].sort((a, b) => {
    const ta = a.createdAt?.seconds || 0;
    const tb = b.createdAt?.seconds || 0;
    return ta - tb;
  });

  let freePool = 5;
  let totalFree = 0;
  let totalPaid = 0;

  for (const prop of sorted) {
    const unitCount = prop.units?.length || 0;
    const freeInThisProp = Math.min(unitCount, freePool);
    
    totalFree += freeInThisProp;
    totalPaid += (unitCount - freeInThisProp);
    freePool -= freeInThisProp;
  }

  return {
    freeUnits: totalFree,
    paidUnits: totalPaid,
    totalCost: totalPaid * 60, // $60 per paid unit
    remainingFreeAllowance: freePool
  };
};
