        background: 'linear-gradient(135deg, #818cf8 0%, #c084fc 50%, #22d3ee 100%)',
        WebkitBackgroundClip: 'text', WebkitTextFillColor: 'transparent',
        marginBottom: 20,
      }}>
        Aurame OS
      </div>
      <div style={{
        fontSize: 15, color: 'rgba(255,255,255,0.7)',
