      }}>
        This workspace is reserved for AURA family members.
        Sign in at <span style={{ color: '#a5b4fc', fontWeight: 600 }}>aurame.ca</span> to enter.
      </div>
      <a href="/" style={{
        display: 'inline-flex', alignItems: 'center', gap: 8,
