      </a>
      <div style={{
        marginTop: 28, fontSize: 10, letterSpacing: 2,
        color: 'rgba(255,255,255,0.25)', textTransform: 'uppercase',
      }}>
        No public access · Family suite
      </div>
    </div>
  );
}

// ── Main App ──────────────────────────────────────────────────────────────────
export default function App() {
  const [booted, setBooted] = useState(false);
  const hubAuraId = getHubParam();
  const sessionStatus = useFamilySession();

  // ── Device-aware routing: phones get the AURA Phone shell, laptops get the OS ──
  useEffect(() => {
    if (typeof window === "undefined") return;
    if (hubAuraId) return;
    const isPhoneViewport = window.matchMedia("(max-width: 899px)").matches;
    const isCoarsePointer = window.matchMedia("(pointer: coarse)").matches;
    const isMobileUA = /android|iphone|ipod|iemobile|blackberry|bb10|mini|windows\sce|palm/i.test(navigator.userAgent);
    const forceDesktop = new URLSearchParams(window.location.search).has("desktop");
    if (!forceDesktop && (isPhoneViewport || (isCoarsePointer && isMobileUA))) {
      window.location.replace(`${window.location.origin}/aura-install/`);
    }
  }, [hubAuraId]);

  // ── TV Hub mode — no boot screen, straight to session display ──
  // (TV Hub is a public family-display surface, no auth needed.)
  if (hubAuraId) {
    return (
      <div style={{ width: '100vw', height: '100vh', overflow: 'hidden', background: '#030108' }}>
        <TVHub auraId={hubAuraId} />
      </div>
    );
  }

  // ── Family session gate ──
  // Brief blank during the synchronous localStorage check; then either show
  // the GuestGate (sign in CTA → landing) or the actual OS shell.
  if (sessionStatus === "checking") {
    return <div style={{ width: '100vw', height: '100vh', background: '#030108' }} />;
  }
  if (sessionStatus === "guest") {
    return <GuestGate />;
  }

  return (
    <div style={{ width: '100vw', height: '100vh', overflow: 'hidden', background: '#030108' }}>
      <AnimatePresence>
        {!booted && <BootScreen key="boot" onDone={() => setBooted(true)} />}
      </AnimatePresence>
      {booted && <Desktop />}
      <IOSInstallBanner />
    </div>
  );
}
