import { useState, useRef, useEffect, useCallback } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { PebbleRichText } from '@/components/PebbleRichText';

interface Msg { id: string; role: 'user' | 'pebble'; text: string; ts: number }
interface PebbleSession { auraId: string; name: string; pebbleName: string; pebbleSkin: string }

const API_BASE = '';

// ── Server-side Lasso (sovereign memory — same DB for all AURA surfaces) ───────
async function loadMsgs(auraId: string): Promise<Msg[]> {
  try {
    const res = await fetch(`${API_BASE}/api/lasso/${encodeURIComponent(auraId)}/messages`);
    if (!res.ok) return [];
    const data = await res.json();
    return (data.messages ?? []).map((m: any) => ({
      id: m.id,
      role: m.role === 'assistant' ? 'pebble' : m.role,
      text: m.content ?? '',
      ts: new Date(m.timestamp).getTime(),
    }));
  } catch { return []; }
}

async function saveMsgToDB(auraId: string, msg: Msg): Promise<void> {
  try {
    fetch(`${API_BASE}/api/lasso/${encodeURIComponent(auraId)}/message`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        id: msg.id,
        role: msg.role === 'pebble' ? 'assistant' : 'user',
        content: msg.text,
        timestamp: new Date(msg.ts).toISOString(),
      }),
    }).catch(() => {});
  } catch {}
}

function getSession(): PebbleSession | null {
  try {
    const raw = localStorage.getItem('aura_session');
    if (!raw) return null;
    const s = JSON.parse(raw);
    return {
      auraId: s.auraId ?? 'guest',
      name: s.firstName ?? s.name ?? 'Sovereign',
      pebbleName: s.pebbleName ?? 'Pebble',
      pebbleSkin: s.pebbleSkin ?? 'Vibe',
    };
  } catch { return null; }
}

async function callPebbleAPI(text: string, session: PebbleSession, history: Msg[]): Promise<string> {
  const ctxHistory = history.slice(-20).map(m => ({ role: m.role === 'pebble' ? 'assistant' : 'user', content: m.text }));
  const res = await fetch(`${API_BASE}/api/pebble/chat`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ message: text, userId: session.auraId, userName: session.name, pebbleName: session.pebbleName, history: ctxHistory }),
  });
  if (!res.ok) throw new Error(await res.text());
  const data = await res.json();
  return data.reply as string;
}

function RobotFace({ size = 28, pulse = false }: { size?: number; pulse?: boolean }) {
  const color = '#38bdf8';
  return (
    <svg viewBox="0 0 100 110" width={size} height={size} overflow="visible">
      <defs>
        <linearGradient id="pa-rb" x1="0%" y1="0%" x2="100%" y2="100%">
          <stop offset="0%" stopColor="white" stopOpacity="0.9" />
          <stop offset="100%" stopColor={color} />
        </linearGradient>
      </defs>
      <line x1="50" y1="28" x2="50" y2="18" stroke={color} strokeWidth="3" strokeLinecap="round" />
      <circle cx="50" cy="15" r="3.5" fill="#fbbf24" />
      <circle cx="50" cy="58" r="30" fill="url(#pa-rb)" />
      <rect x="28" y="46" width="44" height="16" rx="5" fill="#0f172a" opacity="0.85" />
      <rect x="33" y="50" width="10" height="8" rx="2" fill={color} opacity="0.95" />
      <rect x="57" y="50" width="10" height="8" rx="2" fill={color} opacity="0.95" />
      {pulse ? (
        <motion.path d="M 40 76 Q 50 82 60 76" stroke="#1e293b" strokeWidth="2.5" fill="none" strokeLinecap="round"
          animate={{ d: ['M 40 76 Q 50 82 60 76', 'M 40 73 Q 50 78 60 73', 'M 40 76 Q 50 82 60 76'] }}
          transition={{ duration: 0.5, repeat: Infinity }}
        />
      ) : (
        <path d="M 42 75 Q 50 79 58 75" stroke="#1e293b" strokeWidth="2.2" fill="none" strokeLinecap="round" opacity="0.5" />
      )}
    </svg>
  );
}

export function PebbleApp() {
  const session = getSession();
  const [msgs, setMsgs] = useState<Msg[]>([]);
  const [input, setInput] = useState('');
  const [thinking, setThinking] = useState(false);
  const [loaded, setLoaded] = useState(false);
  const [gainLevel, setGainLevel] = useState(87);
  const bottomRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (!session) { setLoaded(true); return; }
    loadMsgs(session.auraId).then(history => {
      const sorted = history.sort((a, b) => a.ts - b.ts);
      if (sorted.length === 0) {
        const greet: Msg = { id: `init-${Date.now()}`, role: 'pebble', text: `Hey ${session.name.split(' ')[0]}! I'm ${session.pebbleName} — your sovereign companion. I remember everything we discuss. What's on your mind?`, ts: Date.now() };
        setMsgs([greet]);
        saveMsgToDB(session.auraId, greet);
      } else {
        setMsgs(sorted);
      }
      setLoaded(true);
    });
  }, []);

  useEffect(() => { bottomRef.current?.scrollIntoView({ behavior: 'smooth' }); }, [msgs, thinking]);

  const send = useCallback(async () => {
    if (!input.trim() || thinking || !session) return;
    const userMsg: Msg = { id: crypto.randomUUID(), role: 'user', text: input.trim(), ts: Date.now() };
    const nextMsgs = [...msgs, userMsg];
    setMsgs(nextMsgs);
    setInput('');
    setThinking(true);
    await saveMsgToDB(session.auraId, userMsg);
    try {
      const reply = await callPebbleAPI(userMsg.text, session, nextMsgs);
      const pebbleMsg: Msg = { id: crypto.randomUUID(), role: 'pebble', text: reply, ts: Date.now() };
      setMsgs(prev => [...prev, pebbleMsg]);
      saveMsgToDB(session.auraId, pebbleMsg);
    } catch (err: any) {
      const errMsg: Msg = { id: crypto.randomUUID(), role: 'pebble', text: `Neural link disrupted — ${(err?.message ?? '').slice(0, 60)}`, ts: Date.now() };
      setMsgs(prev => [...prev, errMsg]);
    } finally {
      setThinking(false);
    }
  }, [input, thinking, msgs, session]);

  if (!loaded) return (
    <div style={{ display: 'flex', flex: 1, height: '100%', alignItems: 'center', justifyContent: 'center', flexDirection: 'column', gap: 12 }}>
      <RobotFace size={40} pulse />
      <div style={{ fontSize: 12, color: 'rgba(255,255,255,0.4)' }}>Loading lasso memory…</div>
    </div>
  );

  if (!session) return (
    <div style={{ display: 'flex', flex: 1, height: '100%', alignItems: 'center', justifyContent: 'center', flexDirection: 'column', gap: 12 }}>
      <RobotFace size={40} />
      <div style={{ fontSize: 12, color: 'rgba(255,255,255,0.4)' }}>Sign in to activate Pebble</div>
    </div>
  );

  return (
    <div style={{ display: 'flex', flexDirection: 'column', height: '100%', fontFamily: 'system-ui, sans-serif' }}>

      {/* Header */}
      <div style={{ padding: '12px 16px', background: 'rgba(56,189,248,0.06)', borderBottom: '1px solid rgba(56,189,248,0.12)', display: 'flex', alignItems: 'center', gap: 12, flexShrink: 0 }}>
        <motion.div
          animate={{ boxShadow: thinking ? ['0 0 10px #38bdf880', '0 0 25px #38bdf8', '0 0 10px #38bdf880'] : '0 0 10px #38bdf840' }}
          transition={{ repeat: Infinity, duration: 1 }}
          style={{ width: 38, height: 38, borderRadius: '50%', background: 'radial-gradient(circle at 38% 38%, white, #38bdf8)', display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0 }}
        >
          <RobotFace size={24} pulse={thinking} />
        </motion.div>
        <div style={{ flex: 1 }}>
          <div style={{ color: '#e2e8f0', fontWeight: 700, fontSize: 13 }}>{session.pebbleName}</div>
          <div style={{ color: '#38bdf8', fontSize: 10, marginTop: 1 }}>
            {thinking ? '⟳ Thinking…' : '✓ Lasso memory active'} · Bonded to {session.name.split(' ')[0]} · Gain {gainLevel}%
          </div>
        </div>
        <input type="range" min={0} max={100} value={gainLevel} onChange={e => setGainLevel(Number(e.target.value))}
          style={{ width: 54, accentColor: '#38bdf8', cursor: 'pointer' }} title="Gain Level" />
      </div>

      {/* Messages */}
      <div style={{ flex: 1, overflow: 'auto', padding: '12px 16px', display: 'flex', flexDirection: 'column', gap: 12 }}>
        <AnimatePresence initial={false}>
          {msgs.map((msg) => (
            <motion.div
              key={msg.id}
              initial={{ opacity: 0, y: 6 }}
              animate={{ opacity: 1, y: 0 }}
              style={{ display: 'flex', justifyContent: msg.role === 'user' ? 'flex-end' : 'flex-start', gap: 8, alignItems: 'flex-end' }}
            >
              {msg.role === 'pebble' && (
                <div style={{ width: 28, height: 28, borderRadius: '50%', background: 'radial-gradient(circle at 38% 38%, white, #38bdf8)', display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0 }}>
                  <RobotFace size={18} />
                </div>
              )}
              <div style={{
                maxWidth: '76%', padding: '10px 14px',
                borderRadius: msg.role === 'user' ? '18px 18px 4px 18px' : '18px 18px 18px 4px',
                background: msg.role === 'user' ? 'rgba(56,189,248,0.18)' : 'rgba(255,255,255,0.06)',
                border: msg.role === 'user' ? '1px solid rgba(56,189,248,0.3)' : '1px solid rgba(255,255,255,0.08)',
                color: 'rgba(255,255,255,0.9)', fontSize: 13, lineHeight: 1.65,
              }}>
                {msg.role === 'pebble'
                  ? <PebbleRichText text={msg.text} accentColor='#38bdf8' />
                  : <span style={{ whiteSpace: 'pre-wrap' }}>{msg.text}</span>}
                <div style={{ fontSize: 9, color: 'rgba(255,255,255,0.25)', marginTop: 4, fontWeight: 600 }}>
                  {new Date(msg.ts).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                </div>
              </div>
              {msg.role === 'user' && (
                <div style={{ width: 28, height: 28, borderRadius: '50%', background: 'rgba(56,189,248,0.25)', border: '1px solid rgba(56,189,248,0.4)', flexShrink: 0, display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 10, fontWeight: 800, color: '#38bdf8' }}>
                  {session.name.split(' ').map(w => w[0]).join('').slice(0, 2).toUpperCase()}
                </div>
              )}
            </motion.div>
          ))}
        </AnimatePresence>

        {thinking && (
          <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} style={{ display: 'flex', gap: 8, alignItems: 'flex-end' }}>
            <div style={{ width: 28, height: 28, borderRadius: '50%', background: 'radial-gradient(circle, white, #38bdf8)', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
              <RobotFace size={18} pulse />
            </div>
            <div style={{ padding: '12px 16px', borderRadius: '18px 18px 18px 4px', background: 'rgba(255,255,255,0.06)', border: '1px solid rgba(255,255,255,0.08)', display: 'flex', gap: 5, alignItems: 'center' }}>
              {[0, 0.2, 0.4].map((d, i) => (
                <motion.div key={i} animate={{ scale: [1, 1.4, 1], opacity: [0.4, 1, 0.4] }} transition={{ repeat: Infinity, duration: 0.8, delay: d }}
                  style={{ width: 6, height: 6, borderRadius: '50%', background: '#38bdf8' }} />
              ))}
            </div>
          </motion.div>
        )}
        <div ref={bottomRef} />
      </div>

      {/* Input */}
      <div style={{ padding: '10px 16px', borderTop: '1px solid rgba(56,189,248,0.1)', display: 'flex', gap: 8, flexShrink: 0 }}>
        <input
          ref={inputRef}
          value={input}
          onChange={e => setInput(e.target.value)}
          onKeyDown={e => { if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); send(); } }}
          placeholder={`Ask ${session.pebbleName} anything…`}
          style={{ flex: 1, background: 'rgba(255,255,255,0.06)', border: '1px solid rgba(56,189,248,0.15)', borderRadius: 12, padding: '9px 14px', color: '#ddd', fontSize: 13, outline: 'none' }}
        />
        <motion.button
          whileTap={{ scale: 0.9 }}
          onClick={send}
          disabled={!input.trim() || thinking}
          style={{ width: 40, height: 40, borderRadius: '50%', background: 'linear-gradient(135deg, #38bdf8, #0ea5e9)', border: 'none', cursor: input.trim() && !thinking ? 'pointer' : 'default', fontSize: 16, opacity: input.trim() && !thinking ? 1 : 0.35 }}
        >
          ↑
        </motion.button>
      </div>

      {/* Lasso memory indicator */}
      <div style={{ padding: '5px 16px 8px', borderTop: '1px solid rgba(255,255,255,0.04)', display: 'flex', alignItems: 'center', gap: 6, flexShrink: 0 }}>
        <div style={{ width: 6, height: 6, borderRadius: '50%', background: '#34d399', boxShadow: '0 0 5px #34d399' }} />
        <div style={{ fontSize: 10, color: 'rgba(255,255,255,0.2)', letterSpacing: '0.08em' }}>LASSO MEMORY · {msgs.length} EXCHANGES · TELEPORTED FROM LANDING PAGE</div>
      </div>
    </div>
  );
}
import

 { useState } from 'react';

const AURA_DASHBOARD = `${window.location.origin}/aura-landing/dashboard`;

const BOOKMARKS = [
  { name: 'AURA Dashboard', url: AURA_DASHBOARD, icon: '✦' },
  { name: 'GitHub', url: 'https://github.com', icon: '🐙' },
  { name: 'Hacker News', url: 'https://news.ycombinator.com', icon: '🔶' },
  { name: 'MDN Docs', url: 'https://developer.mozilla.org', icon: '📚' },
];

export function BrowserApp() {
  const [url, setUrl] = useState('');
  const [inputUrl, setInputUrl] = useState('');
  const [loading, setLoading] = useState(false);
  const [history, setHistory] = useState<string[]>([]);
  const [histIdx, setHistIdx] = useState(-1);

  const navigate = (target: string) => {
    let finalUrl = target;
    if (!target.startsWith('http://') && !target.startsWith('https://')) {
      if (target.includes('.')) finalUrl = 'https://' + target;
      else finalUrl = `https://www.google.com/search?q=${encodeURIComponent(target)}`;
    }
    const newHistory = [...history.slice(0, histIdx + 1), finalUrl];
    setUrl(finalUrl);
    setInputUrl(finalUrl);
    setHistory(newHistory);
    setHistIdx(newHistory.length - 1);
    setLoading(true);
  };

  const goBack = () => {
    if (histIdx <= 0) return;
    const newIdx = histIdx - 1;
    setHistIdx(newIdx);
    setUrl(history[newIdx]);
    setInputUrl(history[newIdx]);
  };

  const goForward = () => {
    if (histIdx >= history.length - 1) return;
    const newIdx = histIdx + 1;
    setHistIdx(newIdx);
    setUrl(history[newIdx]);
    setInputUrl(history[newIdx]);
  };

  return (
    <div style={{ display: 'flex', flexDirection: 'column', height: '100%', fontFamily: 'system-ui, sans-serif' }}>
      {/* Nav bar */}
      <div style={{ display: 'flex', alignItems: 'center', gap: 8, padding: '8px 12px', background: 'rgba(255,255,255,0.04)', borderBottom: '1px solid rgba(255,255,255,0.07)', flexShrink: 0 }}>
        <button onClick={goBack} disabled={histIdx <= 0} style={navBtn(histIdx <= 0)}>‹</button>
        <button onClick={goForward} disabled={histIdx >= history.length - 1} style={navBtn(histIdx >= history.length - 1)}>›</button>
        <button onClick={() => navigate(url)} style={navBtn(false)} title="Reload">↻</button>
        <form onSubmit={e => { e.preventDefault(); navigate(inputUrl); }} style={{ flex: 1, display: 'flex' }}>
          <input
            value={inputUrl}
            onChange={e => setInputUrl(e.target.value)}
            placeholder="Enter URL or search..."
            style={{
              flex: 1, background: 'rgba(255,255,255,0.07)', border: '1px solid rgba(255,255,255,0.12)',
              borderRadius: 8, padding: '5px 12px', color: '#ddd', fontSize: 13, outline: 'none',
            }}
          />
        </form>
      </div>

      {/* Bookmarks */}
      <div style={{ display: 'flex', gap: 6, padding: '4px 12px', background: 'rgba(255,255,255,0.02)', borderBottom: '1px solid rgba(255,255,255,0.05)', flexShrink: 0 }}>
        {BOOKMARKS.map(b => (
          <button
            key={b.url}
            onClick={() => navigate(b.url)}
            style={{ background: 'none', border: 'none', cursor: 'pointer', color: 'rgba(255,255,255,0.6)', fontSize: 12, padding: '2px 8px', borderRadius: 4, display: 'flex', gap: 4 }}
          >
            <span>{b.icon}</span> {b.name}
          </button>
        ))}
      </div>

      {/* Content */}
      {!url ? (
        <div style={{ flex: 1, display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', gap: 24 }}>
          <div style={{ fontSize: 40, color: '#7c3aed' }}>✦</div>
          <div style={{ color: 'rgba(255,255,255,0.4)', fontSize: 13 }}>Navigate to a URL or search the web</div>
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 10 }}>
            {BOOKMARKS.map(b => (
              <button
                key={b.url}
                onClick={() => navigate(b.url)}
                style={{
                  background: 'rgba(255,255,255,0.05)', border: '1px solid rgba(255,255,255,0.08)',
                  borderRadius: 12, padding: '14px 20px', cursor: 'pointer', color: '#ddd', fontSize: 13,
                  display: 'flex', alignItems: 'center', gap: 8,
                }}
              >
                <span style={{ fontSize: 20 }}>{b.icon}</span> {b.name}
              </button>
            ))}
          </div>
        </div>
      ) : (
        <div style={{ flex: 1, position: 'relative' }}>
          {loading && (
            <div style={{ position: 'absolute', top: 0, left: 0, right: 0, height: 3, background: 'rgba(255,255,255,0.05)', zIndex: 10 }}>
              <div style={{ height: '100%', width: '60%', background: 'linear-gradient(90deg, #7c3aed, #4f46e5)', animation: 'none' }} />
            </div>
          )}
          <iframe
            src={url}
            onLoad={() => setLoading(false)}
            style={{ width: '100%', height: '100%', border: 'none' }}
            sandbox="allow-scripts allow-same-origin allow-forms allow-popups"
            title="Browser"
          />
        </div>
      )}
    </div>
  );
}

function navBtn(disabled: boolean): React.CSSProperties {
  return {
    background: 'rgba(255,255,255,0.06)', border: '1px solid rgba(255,255,255,0.1)',
    borderRadius: 6, padding: '4px 10px', cursor: disabled ? 'default' : 'pointer',
    color: disabled ? 'rgba(255,255,255,0.25)' : 'rgba(255,255,255,0.8)', fontSize: 16,
    fontWeight: 300,
  };
}
