function getDefaultPos(appId: string) {
  const map: Record<string, { x: number; y: number }> = {
    files: { x: 60, y: 60 }, terminal: { x: 80, y: 80 }, browser: { x: 100, y: 50 },
    notes: { x: 120, y: 70 }, code: { x: 90, y: 90 }, music: { x: 140, y: 60 },
    calc: { x: 300, y: 100 }, calendar: { x: 70, y: 80 }, store: { x: 80, y: 60 },
    pebble: { x: 200, y: 80 }, settings: { x: 160, y: 70 }, sov: { x: 110, y: 80 }, syncity: { x: 80, y: 60 }, clock: { x: 260, y: 70 }, phone: { x: 140, y: 80 },
