  return map[appId] ?? { x: 80, y: 60 };
}

export function Desktop() {
  const { windows, close, focus, open: openWindow } = useWindowManager();
  const [locked, setLocked] = useState(false);
  const [openCount, setOpenCount] = useState(0);

  const launchApp = useCallback((appId: string) => {
    const manifest = appRegistry.getApp(appId);
    if (!manifest) return;
    const existing = windows.find(w => w.appId === appId && w.state !== 'minimized');
    if (existing) { focus(existing.id); return; }
    systemSounds.windowOpen();
    const pos = getDefaultPos(appId);
    const offset = (openCount % 8) * 20;
    const winId = `${appId}_${Date.now()}`;
    openWindow({ id: winId, appId, title: manifest.name, icon: manifest.icon, color: manifest.color, position: { x: pos.x + offset, y: pos.y + offset }, size: manifest.defaultSize, state: 'normal' });
    setOpenCount(c => c + 1);
    eventBus.emit(SystemEvents.APP_OPENED, { appId });
  }, [windows, focus, openWindow, openCount]);

  const activeApp = windows.filter(w => w.state !== 'minimized').sort((a, b) => b.zIndex - a.zIndex)[0];
  const handleLock = () => { systemSounds.lock(); setLocked(true); };

  // ── Pebble teleport heartbeat — writes to localStorage so the landing page knows the OS is active ──
  useEffect(() => {
    const beat = () => localStorage.setItem('pebble_context', JSON.stringify({ location: 'aurame-os', ts: Date.now() }));
    beat();
    const id = setInterval(beat, 5000);
    return () => {
      clearInterval(id);
      localStorage.removeItem('pebble_context');
    };
  }, []);

  // ── Pebble deep-link launcher — listens for aura:launch events from PebbleRichText ──
  useEffect(() => {
    const handler = (e: Event) => {
      const appId = (e as CustomEvent).detail?.appId;
      if (appId) launchApp(appId);
    };
    document.addEventListener('aura:launch', handler);
    return () => document.removeEventListener('aura:launch', handler);
  }, [launchApp]);

  // ── URL param auto-launch — open app specified in ?launch=appId on OS load ──
  // Also captures ?from=install (or ?from=landing) so the close button can return there.
  useEffect(() => {
    const params = new URLSearchParams(window.location.search);
    const appId = params.get('launch');
    const from = params.get('from');
    if (from === 'install') sessionStorage.setItem('aura_return_to', '/aura-install/');
    else if (from === 'landing') sessionStorage.setItem('aura_return_to', '/');
    if (appId) {
      setTimeout(() => launchApp(appId), 800);
    }
    if (appId || from) {
      const url = new URL(window.location.href);
      url.searchParams.delete('launch');
      url.searchParams.delete('from');
      window.history.replaceState({}, '', url.toString());
    }
  }, []); // eslint-disable-line react-hooks/exhaustive-deps

  // ── Smart return: when the last window closes and we have a return target,
  //    navigate back to where the user came from (install, landing, etc.). ────
  const wasOpenRef = useRef(false);
  useEffect(() => {
    const visible = windows.filter(w => w.state !== 'minimized').length;
    if (visible > 0) wasOpenRef.current = true;
    if (visible === 0 && wasOpenRef.current) {
      const back = sessionStorage.getItem('aura_return_to');
      if (back) {
        sessionStorage.removeItem('aura_return_to');
        window.location.href = back;
      }
    }
  }, [windows]);

  // PWA install prompt
  const [installPrompt, setInstallPrompt] = useState<any>(null);
  const [showInstallBanner, setShowInstallBanner] = useState(false);
  useEffect(() => {
    const handler = (e: any) => { e.preventDefault(); setInstallPrompt(e); setShowInstallBanner(true); };
    window.addEventListener('beforeinstallprompt', handler);
    return () => window.removeEventListener('beforeinstallprompt', handler);
  }, []);
  const handleInstall = async () => {
    if (!installPrompt) return;
    installPrompt.prompt();
    const { outcome } = await installPrompt.userChoice;
    if (outcome === 'accepted') { setShowInstallBanner(false); setInstallPrompt(null); }
  };

  return (
    <div style={{ width: '100vw', height: '100vh', overflow: 'hidden', position: 'relative', userSelect: 'none' }}>
      <Wallpaper />
      <MenuBar activeApp={activeApp?.title} onLockScreen={handleLock} />

      {/* Desktop watermark logo */}
      <div style={{ position: 'fixed', top: '50%', left: '50%', transform: 'translate(-50%,-50%)', zIndex: 0, pointerEvents: 'none', opacity: 0.04 }}>
        <AuraMark size={320} id="watermark" />
      </div>

      {/* Desktop icon grid */}
      <DesktopIcons onLaunch={launchApp} />

      {/* Right-side widgets */}
      <DesktopWidgets />

      {/* Windows */}
      <AnimatePresence>
        {windows.map(win => {
          const AppComponent = APP_COMPONENTS[win.appId];
          if (!AppComponent) return null;
          return (
            <DraggableWindow key={win.id} win={win} onClose={() => eventBus.emit(SystemEvents.APP_CLOSED, { appId: win.appId })}>
              <AppComponent onLock={win.appId === 'settings' ? handleLock : undefined} />
            </DraggableWindow>
          );
        })}
      </AnimatePresence>

      <PebbleBubble />
      <GodViewPanel />
      <InstallPrompt />
      <Dock dockApps={DOCK_APPS} onLaunch={launchApp} />

      {/* PWA Install Banner */}
      <AnimatePresence>
        {showInstallBanner && (
          <motion.div
            initial={{ opacity: 0, y: 60 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: 60 }}
            style={{ position: 'fixed', bottom: 92, left: '50%', transform: 'translateX(-50%)', zIndex: 9997, display: 'flex', alignItems: 'center', gap: 12, padding: '12px 18px', background: 'rgba(10,8,28,0.96)', border: '1px solid rgba(94,92,230,0.4)', borderRadius: 16, boxShadow: '0 8px 40px rgba(0,0,0,0.6)', backdropFilter: 'blur(20px)', whiteSpace: 'nowrap' }}
          >
            <div style={{ fontSize: 20 }}>⬇️</div>
            <div>
              <div style={{ fontSize: 12, fontWeight: 700, color: '#fff' }}>Install Aurame OS</div>
              <div style={{ fontSize: 10, color: 'rgba(255,255,255,0.4)' }}>Works on any device — PC, Mac, TV, tablet</div>
            </div>
            <button onClick={handleInstall} style={{ padding: '6px 16px', borderRadius: 10, background: 'linear-gradient(135deg,#5e5ce6,#bf5af2)', border: 'none', cursor: 'pointer', color: '#fff', fontSize: 12, fontWeight: 700 }}>Install</button>
            <button onClick={() => setShowInstallBanner(false)} style={{ background: 'none', border: 'none', cursor: 'pointer', color: 'rgba(255,255,255,0.3)', fontSize: 16, padding: 0 }}>×</button>
          </motion.div>
        )}
      </AnimatePresence>

      <AnimatePresence>
        {locked && <LockScreen onUnlock={() => setLocked(false)} />}
      </AnimatePresence>
    </div>
  );
}

function DesktopWidgets() {
  const [time, setTime] = useState(new Date());
  const [cpuVal] = useState(() => 25 + Math.floor(Math.random() * 20));
  const [memVal] = useState(() => 12 + Math.floor(Math.random() * 10));
  const [batteryLevel, setBatteryLevel] = useState<number>(100);
  const [batteryCharging, setBatteryCharging] = useState(false);
  const [uptime, setUptime] = useState(0);

  useEffect(() => {
    const id = setInterval(() => { setTime(new Date()); setUptime(s => s + 1); }, 1000);
    const nav = navigator as any;
    if (nav.getBattery) {
      nav.getBattery().then((b: any) => {
        setBatteryLevel(Math.round(b.level * 100));
        setBatteryCharging(b.charging);
        b.addEventListener('levelchange', () => setBatteryLevel(Math.round(b.level * 100)));
        b.addEventListener('chargingchange', () => setBatteryCharging(b.charging));
      });
    }
    return () => clearInterval(id);
  }, []);

  const uptimeStr = uptime < 60 ? `${uptime}s` : uptime < 3600 ? `${Math.floor(uptime / 60)}m` : `${Math.floor(uptime / 3600)}h ${Math.floor((uptime % 3600) / 60)}m`;
  const battColor = batteryLevel > 50 ? '#34c759' : batteryLevel > 20 ? '#febc2e' : '#ff5f57';

  const wDay = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
  const today = time.getDay();
  const weather = [
    { d: wDay[(today + 0) % 7], hi: 72, emoji: '🌙' },
    { d: wDay[(today + 1) % 7], hi: 74, emoji: '⛅' },
    { d: wDay[(today + 2) % 7], hi: 69, emoji: '☁️' },
    { d: wDay[(today + 3) % 7], hi: 65, emoji: '🌧' },
    { d: wDay[(today + 4) % 7], hi: 72, emoji: '🌤' },
  ];

  const glass: React.CSSProperties = {
    background: 'rgba(8,6,28,0.72)', backdropFilter: 'blur(24px)', WebkitBackdropFilter: 'blur(24px)',
    border: '1px solid rgba(255,255,255,0.08)', borderRadius: 20, padding: 18,
    boxShadow: '0 8px 40px rgba(0,0,0,0.45)',
  };

  return (
    <motion.div
      initial={{ opacity: 0, x: 30 }}
      animate={{ opacity: 1, x: 0 }}
      transition={{ delay: 0.5, duration: 0.6, ease: [0.16, 1, 0.3, 1] }}
      style={{ position: 'fixed', top: 52, right: 16, width: 220, display: 'flex', flexDirection: 'column', gap: 10, zIndex: 2, pointerEvents: 'none' }}
    >
      {/* Weather widget */}
      <div style={glass}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
          <div>
            <div style={{ fontSize: 38, fontWeight: 200, color: '#fff', lineHeight: 1, letterSpacing: '-0.03em' }}>72°</div>
            <div style={{ fontSize: 12, fontWeight: 500, color: 'rgba(255,255,255,0.7)', marginTop: 2 }}>Partly Cloudy</div>
            <div style={{ fontSize: 10, color: 'rgba(255,255,255,0.3)', marginTop: 2 }}>San Francisco, CA</div>
          </div>
          <div style={{ fontSize: 36 }}>🌙</div>
        </div>
        <div style={{ marginTop: 14, display: 'flex', justifyContent: 'space-between' }}>
          {weather.map((w, i) => (
            <div key={i} style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 3 }}>
              <div style={{ fontSize: 9, color: 'rgba(255,255,255,0.4)', fontWeight: 600 }}>{w.d}</div>
              <div style={{ fontSize: 15 }}>{w.emoji}</div>
              <div style={{ fontSize: 11, color: 'rgba(255,255,255,0.7)', fontWeight: 500 }}>{w.hi}°</div>
            </div>
          ))}
        </div>
      </div>

      {/* System widget */}
      <div style={glass}>
        <div style={{ fontSize: 9, fontWeight: 700, letterSpacing: '0.16em', color: 'rgba(255,255,255,0.35)', marginBottom: 12 }}>● SYSTEM</div>
        {[
          { label: 'CPU', val: cpuVal, max: 100, unit: '%', color: '#5e5ce6' },
          { label: 'Memory', val: memVal, max: 64, unit: 'GB', color: '#34c759' },
          { label: 'Battery', val: batteryLevel, max: 100, unit: '%', color: battColor, extra: batteryCharging ? ' ⚡' : '' },
        ].map(row => (
          <div key={row.label} style={{ marginBottom: 10 }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 4 }}>
              <span style={{ fontSize: 11, color: 'rgba(255,255,255,0.5)' }}>{row.label}</span>
              <span style={{ fontSize: 11, color: row.color, fontWeight: 600, fontVariantNumeric: 'tabular-nums' }}>{row.val}{row.unit}{row.extra ?? ''}</span>
            </div>
            <div style={{ height: 3, background: 'rgba(255,255,255,0.07)', borderRadius: 2 }}>
              <div style={{ height: '100%', width: `${(row.val / row.max) * 100}%`, background: row.color, borderRadius: 2, transition: 'width 1s ease' }} />
            </div>
          </div>
        ))}
        <div style={{ display: 'flex', gap: 8, marginTop: 4 }}>
          {[
            { label: 'Network', val: '4g · 10Mbps' },
            { label: 'Uptime', val: uptimeStr },
            { label: 'Cores', val: '12' },
          ].map(r => (
            <div key={r.label} style={{ flex: 1 }}>
              <div style={{ fontSize: 9, color: 'rgba(255,255,255,0.3)', marginBottom: 2 }}>{r.label}</div>
              <div style={{ fontSize: 10, color: 'rgba(255,255,255,0.6)', fontWeight: 600 }}>{r.val}</div>
            </div>
          ))}
        </div>
      </div>
    </motion.div>
  );
}

