    return () => clearTimeout(t);
  }, []);

  const color = '#38bdf8'; // Pebble Vibe skin default

  return (
    <div style={{ position: 'fixed', bottom: 80, right: 20, zIndex: 850, display: 'flex', flexDirection: 'column', alignItems: 'flex-end', gap: 8 }}>

