                          {forgeData.units.map((u, i) => (
                            <div key={u.id} className="p-3 bg-white/5 border border-white/10 rounded-xl space-y-2 shadow-inner relative group">
                              <button 
                                onClick={() => setForgeData({...forgeData, units: forgeData.units.filter((_, idx) => idx !== i)})} 
                                className="absolute top-2 right-2 text-slate-500 hover:text-rose-500 transition-colors"
                              >
                                <X size={12}/>
                              </button>
                              
                              <div className="grid grid-cols-2 gap-2">
                                <div className="space-y-0.5">
                                  <label className="text-[6px] font-black text-slate-500 uppercase tracking-widest">Unit Name</label>
