                                    value={u.name} 
                                    onChange={e => {
                                      const newUnits = [...forgeData.units];
                                      newUnits[i].name = e.target.value.toUpperCase();
                                      setForgeData({...forgeData, units: newUnits});
                                    }}
                                    className="w-full p-2 bg-white/5 border border-white/10 rounded-md text-[8px] font-black outline-none uppercase text-white"
