                                        <Image size={7} className="absolute left-1.5 top-1/2 -translate-y-1/2 text-slate-500" />
                                        <input 
                                          placeholder="IMAGE URL"
                                          value={img} 
                                          onChange={e => {
                                            const newUnits = [...forgeData.units];

           newUnits[i].images[imgIdx] = e.target.value;
                                            setForgeData({...forgeData, units: newUnits});
                                          }}
                                          className="w-full p-1 pl-4 bg-white/5 border border-white/10 rounded text-[7px] font-black outline-none text-white"
                                        />
                                        {u.images.length > 1 && (
                                          <button 
                                            onClick={() => {
                                              const newUnits = [...forgeData.units];
                                              newUnits[i].images.splice(imgIdx, 1);
                                              setForgeData({...forgeData, units: newUnits});
                                            }}
                                            className="absolute right-1 top-1/2 -translate-y-1/2 text-slate-500 hover:text-rose-500"
                                          >
                                            <X size={7} />
                                          </button>
                                        )}
                                      </div>
                                    ))}
                                  </div>
                                </div>
                              </div>
                            </div>
                          ))}
                        </div>
                        <div className="flex gap-2">
