                          <button onClick={() => setForgeStep(3)} className="flex-1 py-3 bg-white text-slate-900 rounded-xl font-black text-[9px] uppercase tracking-[0.4em] shadow-2xl hover:bg-indigo-500 hover:text-white transition-all">
                            Review Node Commit
                          </button>
                        </div>
                      </div>
                    ) : (
                      <div className="space-y-4">
                        <div className="text-center space-y-1">
                          <div className="w-10 h-10 bg-indigo-500/10 rounded-full flex items-center justify-center text-indigo-500 mx-auto mb-1">
                            <ShieldCheck size={20} />
                          </div>
                          <h3 className="text-sm font-black uppercase tracking-tighter italic">Commit Confirmation</h3>
                          <p className="text-[8px] font-bold text-slate-500 uppercase tracking-widest">Review your provisioning parameters</p>
                        </div>

                        <div className="bg-white/5 border border-white/10 rounded-2xl p-4 space-y-3">
                          <div className="flex justify-between items-center border-b border-white/5 pb-2">
                            <span className="text-[8px] font-black text-slate-500 uppercase tracking-widest">Node Identifier</span>
                            <span className="text-[9px] font-black text-white uppercase italic">{forgeData.name}</span>
                          </div>
                          <div className="flex justify-between items-center border-b border-white/5 pb-2">
                            <span className="text-[8px] font-black text-slate-500 uppercase tracking-widest">Unit Count</span>
                            <span className="text-[9px] font-black text-white uppercase italic">{forgeData.units.length} Units</span>
                          </div>
                          <div className="flex justify-between items-center">
                            <span className="text-[8px] font-black text-slate-500 uppercase tracking-widest">Monthly Node Cost</span>
                            <div className="text-right">
                              <p className="text-sm font-black text-indigo-500 italic leading-none">
                                ${(() => {
                                  // Calculate total units already provisioned
                                  const existingUnits = properties?.reduce((acc: number, p: any) => acc + (p.units?.length || 0), 0) || 0;
                                  const newUnits = forgeData.units.length;
                                  const totalUnits = existingUnits + newUnits;
                                  
                                  // Total paid units in the new state
                                  const totalPaid = Math.max(0, totalUnits - 5);
                                  // Current paid units
                                  const currentPaid = Math.max(0, existingUnits - 5);
                                  
                                  // Incremental paid units
                                  const incrementalPaid = totalPaid - currentPaid;
                                  return incrementalPaid * 60;
                                })()}/MO
                              </p>
                              <p className="text-[6px] font-black text-emerald-500 uppercase tracking-widest mt-0.5">
                                {properties?.length === 0 ? 'Genesis Node Active' : 'Standard Node Pricing'}
                              </p>
                            </div>
                          </div>
                        </div>

                        <div className="p-3 bg-amber-500/10 border border-amber-500/20 rounded-lg space-y-2">
                          <div className="flex items-start gap-2">
                            <AlertTriangle className="text-amber-500 shrink-0" size={12} />
                            <p className="text-[8px] font-bold text-amber-500 uppercase leading-relaxed">
                              By committing this node, you acknowledge and accept the associated monthly infrastructure costs. This action is irreversible within the current billing cycle.
                            </p>
                          </div>
                          <label className="flex items-center gap-2 cursor-pointer group">
                            <div 
                              onClick={() => setAcceptCosts(!acceptCosts)}
                              className={cn(
                                "w-3 h-3 rounded border flex items-center justify-center transition-all",
                                acceptCosts ? "bg-amber-500 border-amber-500 text-white" : "border-white/10 bg-white/5 group-hover:border-white/30"
                              )}
                            >
                              {acceptCosts && <CheckCircle2 size={8} strokeWidth={3} />}
                            </div>
                            <span className="text-[7px] font-black text-amber-500 uppercase tracking-widest">I accept the extra costs and terms</span>
                          </label>
                        </div>

                        <div className="flex gap-2">
                          <button onClick={() => setForgeStep(2)} className="px-4 bg-white/5 border border-white/10 text-slate-500 rounded-lg text-[7px] font-black uppercase tracking-widest">Back</button>
                          <button onClick={handleForgeSave} disabled={isSavingForge || !acceptCosts} className="flex-1 py-3 bg-indigo-600 text-white rounded-xl font-black text-[9px] uppercase tracking-[0.4em] shadow-2xl hover:bg-white hover:text-slate-900 transition-all disabled:opacity-20">
                            {isSavingForge ? <Loader2 className="animate-spin mx-auto" size={14} /> : 'I Accept & Commit Node'}
                          </button>
                        </div>
                      </div>
                    )}
                  </div>
                </motion.div>
              </>
            )}
          </AnimatePresence>

          <SettingsOverlay 
            isOpen={isSettingsOpen} 
            onClose={() => setIsSettingsOpen(false)} 
            properties={properties || []}
            billingMetrics={billingMetrics}
          />

          <GlobalAssetVisualizer 
            isOpen={isGlobalVisualizerOpen}
            onClose={() => setIsGlobalVisualizerOpen(false)}
            properties={properties || []}
          />
        </main>
      </div>
    </div>
  );
