export const BuildingCommandCenter = ({ property, onBack, propertiesRef, isFirst }: any) => {
  const [selectedUnit, setSelectedUnit] = useState<any>(null);
  const [isEditorOpen, setIsEditorOpen] = useState(false);
  const [activeDetailTab, setActiveDetailTab] = useState<'details' | 'history'>('details');
  const [portalEmail, setPortalEmail] = useState('');
  const [portalUsername, setPortalUsername] = useState('');

  useEffect(() => {
    if (selectedUnit) {
      setPortalEmail(selectedUnit.email || '');
      setPortalUsername(selectedUnit.username || '');
    }
  }, [selectedUnit]);

  const units = property?.units || [];

  const handleOpenEditor = (unit: any) => {
    setSelectedUnit(unit);
    setIsEditorOpen(true);
    setActiveDetailTab('details');
  };

  return (
    <div className="h-full flex flex-col bg-[#0A0B10] text-white overflow-hidden relative">
      {/* Background Glow */}
      <div className="absolute top-0 right-0 w-[600px] h-[600px] bg-indigo-600/10 blur-[120px] rounded-full -mr-40 -mt-40 pointer-events-none" />
      <div className="absolute bottom-0 left-0 w-[400px] h-[400px] bg-purple-600/5 blur-[100px] rounded-full -ml-20 -mb-20 pointer-events-none" />

      <header className="px-6 py-6 border-b border-white/5 flex items-center justify-between shrink-0 relative z-10">
        <div className="flex items-center gap-4">
          <button 
            onClick={onBack}
            className="p-2 hover:bg-white/5 rounded-xl text-slate-500 transition-all"
          >
            <ArrowLeft size={16} />
          </button>
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 rounded-xl bg-white/5 flex items-center justify-center text-indigo-500 border border-white/10 shadow-2xl">
              <Building2 size={20} />
            </div>
            <div className="text-left">
              <h2 className="text-sm font-black uppercase tracking-tighter italic text-white leading-none">
                {property?.name}
                {isFirst && <span className="ml-2 text-[6px] font-black uppercase tracking-widest text-amber-500 bg-amber-500/10 border border-amber-500/20 px-1.5 py-0.5 rounded-md align-middle">Genesis Node</span>}
              </h2>
              <p className="text-[8px] font-black uppercase tracking-[0.2em] text-slate-500 mt-1 flex items-center gap-1.5">
                <MapPin size={8} className="text-indigo-500" /> {property?.address}
              </p>
            </div>
          </div>
        </div>
        <div className="flex items-center gap-1.5">
          {!isFirst && (
            <button className="p-2 bg-rose-500/10 text-rose-500 rounded-lg hover:bg-rose-500/20 transition-all group" title="Decommission Node">
              <Trash2 size={16} />
