            <div className="flex justify-between items-center px-1">
              <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-[0.3em]">Unit Matrix</h3>
              <button className="flex items-center gap-2 text-[10px] font-black text-indigo-400 uppercase tracking-widest hover:text-white transition-colors">
                <Plus size={12} /> Provision Unit
              </button>
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4">
              {units.map((unit: any) => (
                <motion.div 
                  key={unit.id}
                  whileHover={{ y: -4 }}
                  onClick={() => handleOpenEditor(unit)}
                  className="bg-white/5 border border-white/5 rounded-2xl overflow-hidden hover:bg-white/10 transition-all group cursor-pointer flex flex-col"
                >
                  <div className="aspect-video w-full bg-white/5 relative overflow-hidden">
                    {unit.images?.[0] ? (
                      <img 
