                      <div className="w-8 h-8 rounded-lg bg-white/5 flex items-center justify-center text-slate-500 group-hover:text-white transition-colors">
                        <ChevronRight size={14} />
                      </div>
                    </div>
                  </div>
                </motion.div>
              ))}
            </div>
          </div>

          {/* Infrastructure Actions */}
          <div className="pt-2 space-y-2">
            <button className="w-full py-2.5 bg-indigo-600 text-white rounded-xl text-[8px] font-black uppercase tracking-widest shadow-xl shadow-indigo-500/10 hover:bg-indigo-500 transition-all">
              Generate Performance Report
