export function useCollection(ref: Query | null) {
  const [data, setData] = useState<any[] | null>(null);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    if (!ref) {
      setData(null);
      setIsLoading(false);
      return;
    }

    setIsLoading(true);
    return onSnapshot(ref, (snap) => {
      setData(snap.docs.map(d => ({ id: d.id, ...d.data() })));
      setIsLoading(false);
    }, (err) => {
      console.error("Firestore Collection Error:", err);
      setIsLoading(false);
    });
  }, [ref]);

  return { data, isLoading };
}

export function useDoc(ref: DocumentReference | null) {
  const [data, setData] = useState<any | null>(null);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    if (!ref) {
      setData(null);
      setIsLoading(false);
      return;
    }

    setIsLoading(true);
    return onSnapshot(ref, (snap) => {
      setData(snap.exists() ? { id: snap.id, ...snap.data() } : null);
      setIsLoading(false);
    }, (err) => {
      console.error("Firestore Doc Error:", err);
      setIsLoading(false);
    });
  }, [ref]);

  return { data, isLoading };
}

export function useMemoFirebase<T>(factory: () => T, deps: any[]) {
  return useMemo(factory, deps);
}
