@theme {
  --font-mono: "JetBrains Mono", "Roboto Mono", monospace;
  --font-serif: "Georgia", serif;
  
  --color-bg: #000000;
  --color-ink: #ffffff;
  --color-accent: #f27d26; /* Warm orange/gold */
  --color-muted: #8e9299;
  --color-border: rgba(255, 255, 255, 0.1);
  --color-card: #0a0a0a;
