@layer base {
  body {
    @apply bg-[var(--color-bg)] text-[var(--color-ink)] font-sans selection:bg-[var(--color-accent)] selection:text-black;
  }
}

.technical-grid {
  background-image: radial-gradient(circle at 1px 1px, rgba(255, 255, 255, 0.05) 1px, transparent 0);
  background-size: 40px 40px;
}

.glow-text {
  text-shadow: 0 0 20px rgba(242, 125, 38, 0.3);
}

.scanline {
  width: 100%;
  height: 100px;
  z-index: 10;
  background: linear-gradient(0deg, rgba(0, 0, 0, 0) 0%, rgba(242, 125, 38, 0.02) 50%, rgba(0, 0, 0, 0) 100%);
  opacity: 0.1;
  position: absolute;
  bottom: 100%;
  animation: scanline 10s linear infinite;
}

@keyframes scanline {
  0% { bottom: 100%; }
  100% { bottom: -100%; }
